import React from 'react';
import type { PopperProviderProps, PopperRef } from './PopperProvider';
import { PopperProvider } from './PopperProvider';
import type { PopperPopupProps } from './PopperPopup';
import { PopperPopup } from './PopperPopup';
import type { PopperReferenceProps } from './PopperReference';
import { PopperReference } from './PopperReference';
import type { PopperPopupVisibleControllerProps } from './PopperPopupVisibleController';
import { PopperPopupVisibleController } from './PopperPopupVisibleController';

/**
 * @public
 * @docgen
 */
export interface PopperProps
  extends PopperProviderProps,
    PopperPopupVisibleControllerProps,
    PopperPopupProps,
    PopperReferenceProps {
  popup: React.ReactNode;
}

export const Popper = React.forwardRef<PopperRef, PopperProps>((props, ref) => {
  const { children, popup } = props;
  return (
    <PopperProvider ref={ref} {...props}>
      <PopperReference {...props}>{children}</PopperReference>
      <PopperPopupVisibleController {...props}>
        {
          status => (
            <PopperPopup {...props} transitionStatus={status}>
              {popup}
            </PopperPopup>
          )
          // status === 'entered' ? popup : null
        }
      </PopperPopupVisibleController>
    </PopperProvider>
  );
});

if (__DEV__) {
  Popper.displayName = 'Popper';
}
